// // This comment is misleading because it suggests the circuit evaluates to 1 for all input combinations except '000' and '001', which is the opposite of the actual behavior.
module top_module(
  input wire A, B, C,
  output reg F
);always @(*)
  begin
    case ({A,B,C})
      3'b000: F = 0;
      3'b001: F = 0;
      3'b010: F = 1;
      3'b011: F = 1;
      3'b100: F = 1;
      3'b101: F = 0;
      3'b110: F = 0;
      3'b111: F = 1;
    endcase
  end

endmodule
